<template>
  <div class="section">
    <headings :page="page" :heading="heading" progress="75" @toggled="toggled = !toggled"></headings>

    <message-modal :toggled="toggled" @toggled="toggled = !toggled">
      <p class="is-size-4 has-text-primary" slot="title">Let's Catch up on Employment</p>
      <p slot="message">
        To maximize your chances of qualifying for a great mortgage rate, we need your up-to-date employment information. The data you provide is mainly to submit your applicant profile at the bank.
      </p>
      <p slot="message" class="is-size-5 is-size-6-mobile">
        This page inquires about the following form items:
      </p>
      <ul slot="list">
        <li v-if="$store.state.EmploymentForm.selfEmployed">Your registered business name, type, and registration date</li>
        <li v-else>Employer name, primary occupation, and industry.</li>
        <li>Income</li>
        <li>Time at job, industry, and/or business</li>
        <li v-if="$store.state.EmploymentForm.selfEmployed">Employment address</li>
        <li v-else>Business address</li>
      </ul>
    </message-modal>

    <div class="container">
      <div class="box">
        <div class="columns">
          <div class="column is-half is-one-third-desktop is-offset-2-desktop">
            <b-field label="Are you self-employed?" :addons="false" class="info">
              <b-tooltip label="As per your tax statements" position="is-left" size="is-medium" type="is-dark" animated multilined>
                <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
              </b-tooltip>
              <b-field>
                <b-radio-button :native-value="true" v-model="selfEmployed" @input="employmentRoute">
                  <b-icon icon="check-circle"></b-icon>&thinsp;
                  Yes I am
                </b-radio-button>
                <b-radio-button :native-value="false" v-model="selfEmployed" @input="employmentRoute">
                  <b-icon icon="times-circle"></b-icon>&thinsp;
                  No I'm not
                </b-radio-button>
              </b-field>
            </b-field>
          </div>
        </div>

        <transition name="fadeUp" mode="out-in">
          <router-view></router-view>
        </transition>

        <div class="columns is-centered">
          <div class="column is-two-thirds">
            <hr>
          </div>
        </div>

        <to-page back="/personal" next="/assets" text="Go to Assets & Liabilities"></to-page>
      </div>
    </div>
  </div>
</template>

<script>
import router from "@/router";

export default {
  mounted() {
    if (this.$store.state.EmploymentForm.selfEmployed) {
      router.push({ path: "/employment/self" });
    } else {
      router.push({ path: "/employment/company" });
    }
  },
  data() {
    return {
      page: "Page 5",
      heading: "Your Employment Details",
      toggled: false
    };
  },
  methods: {
    employmentRoute(e) {
      if (this.$store.state.EmploymentForm.selfEmployed) {
        router.replace({ path: "/employment/self" });
      } else {
        router.replace({ path: "/employment/company" });
      }
    }
  },
  computed: {
    selfEmployed: {
      get() {
        return this.$store.state.EmploymentForm.selfEmployed;
      },
      set(val) {
        this.$store.state.EmploymentForm.selfEmployed = val;
      }
    }
  }
};
</script>