<template>
  <div class="section">
    <headings :page="page" :heading="heading" progress="100" @toggled="toggled = !toggled"></headings>

    <message-modal :toggled="toggled" @toggled="toggled = !toggled">
      <h5 class="is-size-4 has-text-primary" slot="title">Sign and Submit</h5>
      <p v-if="$store.state.CoApplicantForm.fullName" slot="message">
        To finalize your mortgage application, we need your signatures. Please read the terms carefully, and feel free to backtrack and make necessary adjustments to your application.
      </p>
      <p v-else slot="message">
        Please finalize your mortgage application with your signature. Make sure to read the terms carefully, and feel free to backtrack and make necessary adjustments to your application.
      </p>
    </message-modal>

    <div class="container">
      <div class="box">
        <div class="columns is-centered">
          <div class="column is-two-thirds">
            <section class="content">
              <h1>Disclaimer:</h1>
              <p>
                I, the undersigned, herby declare that all the information provided herein is to the best of my knowledge and belief to be true, complete and correct and I understand that it may be used to determine my credit worthiness. In order to assess my ability to meet my financial obligations I consent and authorize the submitting organization and its agents or assigns:
              </p>
              <ul>
                <li>To request and obtain personal information about me on an ongoing basis from credit bureaus from information you previously collected about me in order to assess my credit history.</li>
                <li>To release and exchange my personal information on an ongoing basis with credit bureaus in order to protect me, ensure the completeness of my information and maintain the integrity of the credit bureau agency:</li>
                <li>To co-operate with local, provincial and national authorities in the investigation of unlawful or improper activities in order to protect myself and Dominioin Lending Centres from fraudulent transactions: and</li>
                <li>To disclose my personal information where necessary to protect my interests, and that of Dominion Lending Centres.</li>
              </ul>
            </section>
          </div>
        </div>

        <div class="columns is-centered">
          <div class="column is-two-thirds">
            <hr>
          </div>
          </div>

          <div class="columns is-centered">
            <div class="column is-5 has-text-centered">
              <p class="has-text-weight-bold">{{$store.state.PersonalForm.fullName}}</p>
              <p class="has-text-weight-bold">Signed on {{formatDate}}</p>
              <canvas ref="applicantSig"></canvas>
              <button class="button is-inverted is-small is-danger" @click="clearSigs($refs.applicantSig)">Erase Signature</button>
            </div>

            <div class="column is-5 has-text-centered" v-if="$store.state.CoApplicantForm.fullName">
              <p class="has-text-weight-bold">{{$store.state.CoApplicantForm.fullName}}</p>
              <p class="has-text-weight-bold">Signed on {{formatDate}}</p>
              <canvas ref="coApplicantSig"></canvas>
              <button class="button is-inverted is-small is-danger" @click="clearSigs($refs.coApplicantSig)">Erase Signature</button>
            </div>
          </div>

          <div class="columns is-centered">
            <div class="column is-two-thirds">
              <hr>
            </div>
          </div>

            <div class="columns is-centered">
              <div class="column is-1 has-text-centered">
                <b-field label="I agree">
                  <b-checkbox v-model="consented"></b-checkbox>
                </b-field>
              </div>
              <div class="column is-7">
                <section class="content">
                  <p>
                    Canada’s new Anti-Spam Legislation is effective as of July 1, 2014. Under this new legislation, I am required to obtain your consent in order to send you communications about the latest mortgage news, events, products and services.
                  </p>
                </section>
              </div>
            </div>

            <div class="columns is-centered">
              <div class="column is-two-thirds has-text-centered">
                <hr>
                <button class="button is-primary is-large is-rounded" @click="submitApplication">Submit My Application</button>
              </div>
            </div>

          </div>
        </div>

      </div>
</template>

<script>
import SignaturePad from "signature_pad";

export default {
  created() {
    window.addEventListener("resize", this.resizeCanvas);
  },
  destroyed() {
    window.removeEventListener("resize", this.resizeCanvas);
  },
  mounted() {
    let vue = this;
    for (const ref in this.$refs) {
      this.$refs[ref] = new SignaturePad(this.$refs[ref], {
        penColor: "rgb(29,42,133)",
        backgroundColor: "rgb(255,255,255)"
      });
      this.$refs[ref].onBegin = function(e) {
        vue.$store.state.SignaturesForm.applicantSignatures.length = 0;
        vue.$store.state.SignaturesForm.coApplicantSignatures.length = 0;
      };
      this.$refs[ref].onEnd = function(e) {
        vue.saveSigs();
      };
    }
  },
  data() {
    return {
      page: "Page 8",
      heading: "Your Signatures",
      toggled: false
    };
  },
  methods: {
    resizeCanvas() {
      var ratio = Math.max(window.devicePixelRatio || 1, 1);
      for (let ref in this.$refs) {
        this.$refs[ref].canvas.width = this.$refs[ref].canvas.width * ratio;
        this.$refs[ref].canvas.height = this.$refs[ref].canvas.height * ratio;
        this.$refs[ref].canvas.getContext("2d").scale(ratio, ratio);
        this.$refs[ref].clear();
      }
    },
    clearSigs(e) {
      e.clear();
      this.$store.state.SignaturesForm.applicantSignatures.length = 0;
      this.$store.state.SignaturesForm.coApplicantSignatures.length = 0;
    },
    saveSigs() {
      for (const sig in this.$refs) {
        const signatureJPG = this.$refs[sig].toDataURL("image/jpeg");
        const signatureSVG = this.$refs[sig].toDataURL("image/svg+xml");
        if (sig === "applicantSig") {
          this.$store.state.SignaturesForm.applicantSignedOn = this.formatDate;
          this.$store.state.SignaturesForm.applicantSignatures.push(
            signatureJPG,
            signatureSVG
          );
        }
        if (sig === "coApplicantSig") {
          this.$store.state.SignaturesForm.coApplicantSignedOn = this.formatDate;
          this.$store.state.SignaturesForm.coApplicantSignatures.push(
            signatureJPG,
            signatureSVG
          );
        }
      }
    },
    submitApplication() {
      this.$store.state.submittedOn = new Date().toLocaleDateString("en-US", {
        weekday: "short",
        year: "numeric",
        month: "long",
        day: "numeric"
      });
      this.$store.state.applicant = this.$store.state.PersonalForm.fullName;
      this.$store.state.complete = true;

      const submission = JSON.stringify(this.$store.state);
    }
  },
  computed: {
    formatDate() {
      return new Date().toLocaleDateString("en-US", {
        weekday: "short",
        year: "numeric",
        month: "long",
        day: "numeric"
      });
    },
    consented: {
      get() {
        return this.$store.state.SignaturesForm.CASL;
      },
      set(val) {
        this.$store.state.SignaturesForm.CASL = val;
      }
    }
  }
};
</script>

<style>
canvas {
  border: 1px solid gainsboro;
  border-bottom-color: black;
  border-bottom-width: 3px;
  border-radius: 6px;
  display: block;
  margin: 8px auto;
}
</style>
