<template>
  <div class="section">

    <headings :page="page" :heading="heading" progress="0" @toggled="toggled = !toggled"></headings>

    <message-modal :toggled="toggled" @toggled="toggled = !toggled">
      <p class="is-size-4 has-text-primary" slot="title">Getting Started</p>
      <p slot="message">
        Thank you for choosing Giraffo. We are look forward to finding the perfect mortgage for your needs. You've made an big decision, and we are here to help you along every step of the way. The application is broken down into simple and straightforward steps to make sure you don't get lost or confused. Each section will have a similar information bar to provide an overview of what you need to fill out. Also, most form fields are marked with a question mark you can hover or tap for helpful tips.
      </p>
      <p slot="message">Sounds good? Feel free to close this message, and let's get started.</p>
      <p slot="message" class="is-size-5 is-size-6-mobile">
        This page inquires about the following form items:
      </p>
      <ul slot="list">
        <li>Are you buying a house or a condo?</li>
        <li>Do you plan on living on this property or renting it out?</li>
        <li>Are you the sole applicant on the mortgage?</li>
      </ul>
    </message-modal>

    <div class="container box">
      <div class="columns is-centered">
        <div class="column is-one-third-tablet">
          <b-field label="Property type" :addons="false" class="info">
            <b-tooltip label="Are you buying a house or a condo?" position="is-left" size="is-medium" type="is-dark" animated multilined>
              <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
            </b-tooltip>
            <b-select v-model="propertyType" placeholder="I need a mortgage for a" expanded>
              <option value="House">House</option>
              <option value="Condo">Condo</option>
            </b-select>
          </b-field>
          <b-field label="Occupancy type" :addons="false" class="info">
            <b-tooltip label="Is the property for rent?" position="is-left" size="is-medium" type="is-dark" animated multilined>
              <i class="fas fa-question-circle" aria-label="additionala info" role="note"></i>
            </b-tooltip>
            <b-select v-model="occupancyType" placeholder="The property will be" expanded>
              <option value="occupant">Owner occupied</option>
              <option value="rental">Rented out</option>
            </b-select>
          </b-field>
        </div>
      </div>

      <transition name="fadeUp">
        <div class="columns is-centered" v-if="occupancyType === 'rental'">
          <div class="column is-one-third-tablet">
            <b-field label="Ownership type" :addons="false" class="info">
              <b-tooltip label="Who will collect the rent?" position="is-left" size="is-medium" type="is-dark" animated multilined>
                <i class="fas fa-question-circle" aria-label="additionala info" role="note"></i>
              </b-tooltip>
              <b-select v-model="ownershipType" placeholder="The rental will by under my" expanded>
                <option value="Personal name">Personal name</option>
                <option value="Holding company">Holding company</option>
                <option value="Operating company">Operating company</option>
              </b-select>
            </b-field>
          </div>
        </div>
      </transition>

      <div class="columns is-centered">
        <div class="column is-one-third-tablet">
          <b-field label="Applicants" :addons="false" class="info">
            <b-tooltip label="How many people will be on the mortgage?" position="is-left" size="is-medium" type="is-dark" animated multilined>
              <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
            </b-tooltip>
            <b-select v-model="applicants" placeholder="I will need form(s) for" expanded>
              <option value="1">Myself</option>
              <option value="2">Two of us</option>
            </b-select>
          </b-field>
        </div>
      </div>

      <div class="columns is-centered">
        <div class="column is-two-thirds">
          <hr>
        </div>
      </div>

      <to-page back="/" next="/property" text="Go to Detailed Property Form"></to-page>
    </div>
  </div>

</template>

<script>
export default {
  created() {
    this.$data.toggled = JSON.parse(localStorage.getItem("tips"));
  },
  destroyed() {
    localStorage.setItem("tips", String(this.toggled));
  },
  data() {
    return {
      page: "Page 1",
      heading: "Preliminary Information",
      toggled: true
    };
  },
  computed: {
    propertyType: {
      get() {
        return this.$store.state.StartForm.propertyType;
      },
      set(val) {
        this.$store.state.StartForm.propertyType = val;
      }
    },
    occupancyType: {
      get() {
        return this.$store.state.StartForm.occupancyType;
      },
      set(val) {
        this.$store.state.StartForm.occupancyType = val;
      }
    },
    ownershipType: {
      get() {
        return this.$store.state.StartForm.ownershipType;
      },
      set(val) {
        this.$store.state.StartForm.ownershipType = val;
      }
    },
    applicants: {
      get() {
        return this.$store.state.StartForm.applicants;
      },
      set(val) {
        this.$store.state.StartForm.applicants = val;
      }
    }
  }
};
</script>

<style lang="scss">
.is-borderless {
  border: none !important;
}
.field.info {
  position: relative;
  span[data-label] {
    position: absolute;
    top: 4px;
    right: 0.925rem;
    cursor: help;
  }
  .fas.fa-question-circle {
    font-size: 17px;
    line-height: 1;
  }
  & > label {
    padding-right: 2em;
  }
}
</style>